terraform {
  required_version = ">= 1.5.0"

  required_providers {
    huaweicloud = {
      source  = "huaweicloud/huaweicloud"
      version = "~> 1.93"
    }
  }
}

variable "region" {
  type        = string
  description = "Huawei Cloud region"
}

variable "vpc_name" {
  type = string
}

variable "vpc_cidr" {
  type = string
}

variable "rds_password" {
  type      = string
  sensitive = true
}
